pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract Deposits {
    using SafeERC20 for IERC20;

    IERC20 public immutable token;
    mapping(address => uint256) public balances;

    constructor(IERC20 _token) { token = _token; }

    function deposit(uint256 amount) external {
        // SafeERC20 handles tokens that return false AND tokens that
        // return nothing at all (e.g. USDT): it reverts on failure.
        token.safeTransferFrom(msg.sender, address(this), amount);
        balances[msg.sender] += amount;
    }

    function withdraw(uint256 amount) external {
        balances[msg.sender] -= amount;
        token.safeTransfer(msg.sender, amount);
    }

    // Minimal alternative without SafeERC20 (only for tokens that
    // are known to return a bool):
    // require(token.transfer(to, amount), "transfer failed");
}
